frappe.ui.form.on('active_taq', {
    refresh: function(frm) {
        frm.trigger('render_counts_display');
    },
    are_you_counts: function(frm) {
        frm.trigger('render_counts_display');
    },
    render_counts_display: function(frm) {
        let container = frm.fields_dict.counts_display.wrapper;
        $(container).empty();

        let data = {};
        let text_value = frm.doc.are_you_counts || '';

        // تحليل النص سطرًا بسطر
        let lines = text_value.split('\n');
        lines.forEach(line => {
            if (line.includes(':')) {
                let parts = line.split(':');
                let key = parts[0].trim();
                let val = parts.slice(1).join(':').trim();
                if (key) {
                    data[key] = val;
                }
            }
        });

        // تم ضبط الخلفية لتطابق تماماً حقول النظام الرمادية الفاتحة #f4f5f7
        let html = `
            <div style="
                background: #f4f5f7;
                border-radius: 8px;
                padding: 16px;
                margin-top: 4px;
                direction: rtl;
            ">
                <!-- عنوان الحقل الإحصائي متناسق مع حجم خط عناوين النظام -->
                <div style="
                    font-size: 12px; 
                    color: #64748b; 
                    font-weight: 600; 
                    margin-bottom: 12px;
                    text-align: right;
                    direction: ltr;
                ">
                    Total Interest Responses
                </div>

                <div style="display: flex; gap: 16px; flex-wrap: wrap;">
        `;

        let has_data = false;
        for (let key in data) {
            has_data = true;
            let badge_color = '#64748b';
            if (key.toLowerCase() === 'yes') badge_color = '#28a745';
            if (key.toLowerCase() === 'no') badge_color = '#dc3545';

            html += `
                <div style="
                    flex: 1;
                    min-width: 140px;
                    background: #ffffff;
                    border: 1px solid #e2e8f0;
                    border-radius: 6px;
                    padding: 12px;
                    text-align: center;
                    box-shadow: 0 1px 2px rgba(0, 0, 0, 0.02);
                ">
                    <div style="font-size: 13px; color: ${badge_color}; font-weight: 600;">${key}</div>
                    <div style="font-size: 22px; font-weight: 700; color: #1e293b; margin-top: 4px;">${data[key]}</div>
                </div>
            `;
        }

        if (!has_data) {
            html += `<div style="color: #94a3b8; font-style: italic; font-size: 13px; text-align: center; width: 100%;">لا توجد بيانات إحصائية متوفرة حالياً.</div>`;
        }

        html += `</div></div>`;
        
        $(container).html(html);
    }
});

